struct ReverseOsmosisWaterFluxEngine: Sendable { func calculate(_ input: ReverseOsmosisWaterFluxInput) throws -> ReverseOsmosisWaterFluxResult { let v=[input.hydraulicPressureDifference,input.osmoticPressureDifference,input.waterPermeability,input.targetPermeateFlow,input.recoveryFraction]; guard v.allSatisfy(\.isFinite) else { throw ReverseOsmosisWaterFluxError.nonFiniteInput }; guard input.waterPermeability>0,input.targetPermeateFlow>0 else { throw ReverseOsmosisWaterFluxError.nonPositivePermeabilityOrFlow }; let ndp=input.hydraulicPressureDifference-input.osmoticPressureDifference; guard ndp>0 else { throw ReverseOsmosisWaterFluxError.nonPositiveNetDrivingPressure }; guard input.recoveryFraction>0,input.recoveryFraction<1 else { throw ReverseOsmosisWaterFluxError.invalidRecovery }; let j=input.waterPermeability*ndp; let a=input.targetPermeateFlow/j; let f=input.targetPermeateFlow/input.recoveryFraction; let c=f-input.targetPermeateFlow; guard [ndp,j,a,f,c].allSatisfy(\.isFinite),a>0 else { throw ReverseOsmosisWaterFluxError.numericalFailure }; return .init(netDrivingPressure:ndp,waterFlux:j,requiredMembraneArea:a,requiredFeedFlow:f,concentrateFlow:c,modelName:"Solution-diffusion reverse-osmosis water flux",limitationDescription:"Uses Jw = A(deltaP - deltaPi) and an entered overall recovery.") } }
